source_patch:
diff --git a/llvm/lib/Transforms/InstCombine/InstCombineSimplifyDemanded.cpp b/llvm/lib/Transforms/InstCombine/InstCombineSimplifyDemanded.cpp
index c58bfaa46792c..2cebc53915921 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineSimplifyDemanded.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineSimplifyDemanded.cpp
@@ -2177,8 +2177,6 @@ Value *InstCombinerImpl::SimplifyDemandedUseFPClass(Value *V,
     // X * -0.0 --> copysign(0.0, -X)

     // TODO: Apply knowledge of no-infinity returns to sources.
-
-    // TODO: Known -0, turn into copysign(y, fneg(x)) like visitFMul.
     if (KnownLHS.isKnownNeverInfOrNaN() &&
         KnownRHS.isKnownAlways(fcPosZero | fcNan)) {
       // => copysign(+0, lhs)
@@ -2197,6 +2195,26 @@ Value *InstCombinerImpl::SimplifyDemandedUseFPClass(Value *V,
       return Copysign;
     }

+    if (KnownLHS.isKnownNeverInfOrNaN() &&
+        KnownRHS.isKnownAlways(fcNegZero | fcNan)) {
+      // => copysign(0, fneg(lhs))
+      // Note: Dropping canonicalize
+      Value *Copysign =
+          Builder.CreateCopySign(Y, Builder.CreateFNegFMF(X, FMF), FMF);
+      Copysign->takeName(I);
+      return Copysign;
+    }
+
+    if (KnownLHS.isKnownAlways(fcNegZero | fcNan) &&
+        KnownRHS.isKnownNeverInfOrNaN()) {
+      // => copysign(+0, fneg(rhs))
+      // Note: Dropping canonicalize
+      Value *Copysign =
+          Builder.CreateCopySign(X, Builder.CreateFNegFMF(Y, FMF), FMF);
+      Copysign->takeName(I);
+      return Copysign;
+    }
+
     Type *EltTy = VTy->getScalarType();
     DenormalMode Mode = F.getDenormalMode(EltTy->getFltSemantics());

tests.source_program:
define nofpclass(snan) float @known__not_inf_or_nan__fmul__nzero_or_nan(float nofpclass(nan inf) %not.inf.or.nan, float nofpclass(inf pzero sub norm) %nzero.or.nan) {
  %mul = fmul contract float %not.inf.or.nan, %nzero.or.nan
  ret float %mul
}

define nofpclass(snan) float @known__nzero_or_nan__fmul__not_inf_or_nan(float nofpclass(inf pzero sub norm) %nzero.or.nan, float nofpclass(nan inf) %not.inf.or.nan) {
  %mul = fmul contract float %nzero.or.nan, %not.inf.or.nan
  ret float %mul
}

declare nofpclass(nan inf sub norm) float @returns_zero()

define nofpclass(ninf) float @ret_ninf__fmul_nnan_unknown__zero(float %unknown) {
  %zero = call float @returns_zero()
  %fmul = fmul nnan float %unknown, %zero
  ret float %fmul
}
